import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  FlatList,
  StyleSheet,
  Alert,
  Platform,
  AppState,
} from 'react-native';
import NetInfo from '@react-native-community/netinfo';
import AsyncStorage from '@react-native-async-storage/async-storage';

const STORAGE_KEY = '@offline_tokens';
const SESSION_KEY = '@current_session';
const ACTION_LOG_KEY = '@action_log';

// Token Generator Utility - Cross-platform, no native dependencies
const TokenGenerator = {
  generateRandomString(length) {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let result = '';
    for (let i = 0; i < length; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return result;
  },

  generateHexSegment(length) {
    const hexChars = '0123456789abcdef';
    let result = '';
    for (let i = 0; i < length; i++) {
      result += hexChars.charAt(Math.floor(Math.random() * hexChars.length));
    }
    return result;
  },

  generateSessionToken() {
    const timestamp = Date.now().toString(36);
    const randomPart = this.generateRandomString(16);
    const platformPrefix = Platform.OS === 'ios' ? 'iOS' : 'AND';
    return `${platformPrefix}-${timestamp}-${randomPart}`;
  },

  generateActionToken(actionType) {
    const timestamp = Date.now().toString(36);
    const randomPart = this.generateHexSegment(8);
    const actionPrefix = (actionType || 'GEN').substring(0, 3).toUpperCase();
    return `ACT-${actionPrefix}-${timestamp}-${randomPart}`;
  },

  generateUUIDv4() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.floor(Math.random() * 16);
      const v = c === 'x' ? r : (r & 0x3) | 0x8;
      return v.toString(16);
    });
  },

  generateOfflineToken() {
    const uuid = this.generateUUIDv4();
    const timestamp = Date.now();
    const checksum = this.generateHexSegment(4);
    return {
      id: uuid,
      token: `OFL-${uuid}-${checksum}`,
      createdAt: timestamp,
      expiresAt: timestamp + 24 * 60 * 60 * 1000, // 24 hours
      platform: Platform.OS,
      isOffline: true,
      synced: false,
    };
  },

  isTokenExpired(tokenObj) {
    return Date.now() > tokenObj.expiresAt;
  },

  isTokenValid(tokenObj) {
    if (!tokenObj || !tokenObj.token || !tokenObj.expiresAt) {
      return false;
    }
    return !this.isTokenExpired(tokenObj);
  },
};

// Offline Session Manager
const SessionManager = {
  currentSession: null,

  async startSession() {
    const sessionToken = TokenGenerator.generateSessionToken();
    const session = {
      sessionToken,
      startedAt: Date.now(),
      actions: [],
      isOffline: true,
      platform: Platform.OS,
    };
    this.currentSession = session;
    await AsyncStorage.setItem(SESSION_KEY, JSON.stringify(session));
    return session;
  },

  async endSession() {
    if (this.currentSession) {
      this.currentSession.endedAt = Date.now();
      this.currentSession.duration =
        this.currentSession.endedAt - this.currentSession.startedAt;
      await AsyncStorage.setItem(SESSION_KEY, JSON.stringify(this.currentSession));
      const session = { ...this.currentSession };
      this.currentSession = null;
      return session;
    }
    return null;
  },

  async logAction(actionType, metadata = {}) {
    if (!this.currentSession) {
      await this.startSession();
    }
    const actionToken = TokenGenerator.generateActionToken(actionType);
    const action = {
      actionToken,
      actionType,
      timestamp: Date.now(),
      metadata,
    };
    this.currentSession.actions.push(action);
    await AsyncStorage.setItem(SESSION_KEY, JSON.stringify(this.currentSession));
    return action;
  },

  async getCurrentSession() {
    if (this.currentSession) return this.currentSession;
    try {
      const stored = await AsyncStorage.getItem(SESSION_KEY);
      if (stored) {
        this.currentSession = JSON.parse(stored);
        return this.currentSession;
      }
    } catch (e) {
      console.warn('Failed to load session:', e);
    }
    return null;
  },
};

// Token Storage Manager
const TokenStorage = {
  async saveToken(tokenObj) {
    try {
      const existing = await this.getAllTokens();
      existing.push(tokenObj);
      await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(existing));
      return true;
    } catch (e) {
      console.warn('Failed to save token:', e);
      return false;
    }
  },

  async getAllTokens() {
    try {
      const stored = await AsyncStorage.getItem(STORAGE_KEY);
      return stored ? JSON.parse(stored) : [];
    } catch (e) {
      console.warn('Failed to load tokens:', e);
      return [];
    }
  },

  async getValidTokens() {
    const tokens = await this.getAllTokens();
    return tokens.filter((t) => TokenGenerator.isTokenValid(t));
  },

  async getUnsyncedTokens() {
    const tokens = await this.getAllTokens();
    return tokens.filter((t) => !t.synced && TokenGenerator.isTokenValid(t));
  },

  async markTokensSynced(tokenIds) {
    try {
      const tokens = await this.getAllTokens();
      const updated = tokens.map((t) => {
        if (tokenIds.includes(t.id)) {
          return { ...t, synced: true, syncedAt: Date.now() };
        }
        return t;
      });
      await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
      return true;
    } catch (e) {
      console.warn('Failed to mark tokens synced:', e);
      return false;
    }
  },

  async purgeExpiredTokens() {
    try {
      const tokens = await this.getAllTokens();
      const valid = tokens.filter(
        (t) => !TokenGenerator.isTokenExpired(t) || !t.synced
      );
      await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(valid));
      return tokens.length - valid.length;
    } catch (e) {
      console.warn('Failed to purge tokens:', e);
      return 0;
    }
  },

  async clearAllTokens() {
    try {
      await AsyncStorage.removeItem(STORAGE_KEY);
      await AsyncStorage.removeItem(SESSION_KEY);
      await AsyncStorage.removeItem(ACTION_LOG_KEY);
      return true;
    } catch (e) {
      console.warn('Failed to clear tokens:', e);
      return false;
    }
  },
};

